#!/usr/bin/env node
/*
 * I-12 — OpenAPI ↔ TypeScript generator.
 *
 * Reads every `docs/openapi/*.yaml` spec and writes a corresponding
 * TypeScript file into `packages/common/src/generated/<name>.ts`. The
 * generated files are committed so that downstream consumers (and the
 * `@euno/common` build itself) do not need to run `openapi-typescript`
 * to type-check.
 *
 * Two modes:
 *
 *   node scripts/generate-openapi-types.mjs           # (re)write the files
 *   node scripts/generate-openapi-types.mjs --check   # exit 1 on drift
 *
 * The `--check` mode is intended for CI: it regenerates the artefacts in
 * memory and compares them byte-for-byte against the committed copies,
 * failing the build if the OpenAPI specs and the generated wire types
 * have drifted apart.
 *
 * See I-12 in `docs/IMPROVEMENTS_AND_REFACTORING.md`.
 */

import { readFile, writeFile, mkdir, readdir, unlink } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import { fileURLToPath, pathToFileURL } from 'node:url';
import path from 'node:path';
import openapiTS, { astToString } from 'openapi-typescript';

const __filename = fileURLToPath(import.meta.url);
const repoRoot = path.resolve(path.dirname(__filename), '..');
const specsDir = path.join(repoRoot, 'docs', 'openapi');
const outDir = path.join(repoRoot, 'packages', 'common', 'src', 'generated');

const HEADER_LINES = [
  '/**',
  ' * AUTO-GENERATED FILE — DO NOT EDIT BY HAND.',
  ' *',
  ' * Regenerate with `npm run gen:openapi` from the repository root.',
  ' * Source spec: docs/openapi/__SPEC__',
  ' *',
  ' * Generated by `openapi-typescript` as part of I-12 in',
  ' * `docs/IMPROVEMENTS_AND_REFACTORING.md` to keep the wire types in',
  ' * `@euno/common` in sync with the OpenAPI contracts in `docs/openapi/`.',
  ' */',
  '/* eslint-disable */',
  '',
];

async function listSpecs() {
  const entries = await readdir(specsDir);
  return entries
    .filter((name) => name.endsWith('.yaml') || name.endsWith('.yml'))
    .sort()
    .map((name) => ({
      name,
      stem: name.replace(/\.ya?ml$/, ''),
      absPath: path.join(specsDir, name),
    }));
}

function header(specFileName) {
  return HEADER_LINES.map((line) => line.replace('__SPEC__', specFileName)).join('\n');
}

async function generateOne(spec) {
  const ast = await openapiTS(pathToFileURL(spec.absPath));
  const body = astToString(ast);
  // openapi-typescript may or may not terminate with a newline depending on
  // version; normalize so the committed file always ends with exactly one.
  const normalizedBody = body.endsWith('\n') ? body : `${body}\n`;
  return `${header(spec.name)}\n${normalizedBody}`;
}

async function listExistingGenerated() {
  if (!existsSync(outDir)) return [];
  const entries = await readdir(outDir);
  return entries.filter((name) => name.endsWith('.ts'));
}

async function main() {
  const checkMode = process.argv.includes('--check');
  const specs = await listSpecs();

  if (specs.length === 0) {
    console.error(`No OpenAPI specs found in ${specsDir}`);
    process.exit(1);
  }

  if (!checkMode && !existsSync(outDir)) {
    await mkdir(outDir, { recursive: true });
  }

  const expectedFiles = new Set(specs.map((spec) => `${spec.stem}.ts`));
  const existingFiles = await listExistingGenerated();
  const staleFiles = existingFiles.filter((name) => !expectedFiles.has(name));

  const drifted = [];
  for (const spec of specs) {
    const outPath = path.join(outDir, `${spec.stem}.ts`);
    const generated = await generateOne(spec);

    if (checkMode) {
      let existing = '';
      try {
        existing = await readFile(outPath, 'utf8');
      } catch (err) {
        if (err && err.code === 'ENOENT') {
          drifted.push({ spec: spec.name, outPath, reason: 'missing' });
          continue;
        }
        throw err;
      }
      if (existing !== generated) {
        drifted.push({ spec: spec.name, outPath, reason: 'out-of-date' });
      }
    } else {
      await writeFile(outPath, generated, 'utf8');
      console.log(`✔ ${path.relative(repoRoot, spec.absPath)} → ${path.relative(repoRoot, outPath)}`);
    }
  }

  if (checkMode) {
    for (const stale of staleFiles) {
      drifted.push({
        spec: '(no spec)',
        outPath: path.join(outDir, stale),
        reason: 'stale (no matching spec)',
      });
    }
    if (drifted.length > 0) {
      console.error('OpenAPI generated types are out of date:');
      for (const d of drifted) {
        console.error(`  - ${d.spec} → ${path.relative(repoRoot, d.outPath)} (${d.reason})`);
      }
      console.error('\nRun `npm run gen:openapi` and commit the result.');
      process.exit(1);
    }
    console.log(`✔ OpenAPI generated types are in sync (${specs.length} spec${specs.length === 1 ? '' : 's'} checked).`);
  } else {
    for (const stale of staleFiles) {
      const stalePath = path.join(outDir, stale);
      await unlink(stalePath);
      console.log(`🗑 removed stale ${path.relative(repoRoot, stalePath)} (no matching spec)`);
    }
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
